   195→    }
   196→
   197→    try {
   198→      const res = await fetch(this.apiEndpoint, {
   199→        method: 'POST',
   200→        headers: {
   201→          'Content-Type': 'application/json',
   202→          'Authorization': `Bearer ${this.apiKey}`
   203→        },
   204→        body: JSON.stringify({
   205→          model: this.model,
   206→          messages: [{ role: 'user', content: prompt }],
   207→          max_tokens: maxTokens,
