   379→class CustomProvider {
   380→  constructor() {
   381→    this.apiKey    = localStorage.getItem('ai_model_custom_key')       || '';
   382→    this.baseUrl   = (localStorage.getItem('ai_model_custom_baseurl')   || '').replace(/\/+$/, '');
