   419→        if (this.authStyle === 'x-api-key') headers['x-api-key'] = this.apiKey;
   420→        else headers['Authorization'] = `Bearer ${this.apiKey}`;
   421→        res = await fetch(`${this.baseUrl}/chat/completions`, {
   422→          method: 'POST',
   423→          headers,
   424→          body: JSON.stringify({ model: this.model, max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] })
   425→        });
   426→        data = await res.json();
   427→        if (!res.ok || data.error) {
   428→          const message = data?.error?.message || `HTTP ${res.status}`;
   429→          const err = new Error(message);
   430→          err.errorType = data?.error?.type || 'api_error';
   431→          err.errorMessage = message;
   432→          throw err;
   433→        }
   434→        return data?.choices?.[0]?.message?.content || '';
   435→      }
   436→    } catch (e) {
   437→      if (e.errorType) throw e;
   438→      const err = new Error(e.message);
   439→      err.errorType = 'network_error';
   440→      err.errorMessage = e.message;
   441→      throw err;
   442→    }
   443→  }
   444→}
